<!DOCTYPE html>
<html lang="th">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
<title>ผังที่นั่ง — งานแต่งงาน</title>
<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400;1,700&family=Great+Vibes&family=Sarabun:wght@300;400;500&display=swap" rel="stylesheet"/>
<style>
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
:root {
  --rose:       #e8a0b4;
  --rose-deep:  #d4607c;
  --rose-light: #f9dde6;
  --rose-pale:  #fef4f7;
  --blush:      #fff0f4;
  --petal:      #fce8ef;
  --gold:       #d4a574;
  --gold-soft:  #e8c49a;
  --ivory:      #fdfaf6;
  --text-h:     #7a3349;
  --text-b:     #a05570;
  --text-s:     #c899aa;
  --green:      #6bbf8e;
  --green-pale: #e0f7ec;
  --green-dark: #3a9d6b;
  --shadow:     rgba(212,96,124,0.12);
}
body {
  font-family: 'Sarabun', sans-serif;
  min-height: 100vh;
  background: var(--blush);
  display: flex; flex-direction: column; align-items: center;
  padding: 0 0 80px;
  position: relative; overflow-x: hidden;
}
body::before {
  content: ''; position: fixed; inset: 0; z-index: 0;
  background:
    radial-gradient(ellipse 100% 55% at 50% 0%,   #fad8e588 0%, transparent 70%),
    radial-gradient(ellipse 70%  50% at 0%   100%, #fce8ef55 0%, transparent 70%),
    radial-gradient(ellipse 60%  40% at 100% 80%,  #fad2df44 0%, transparent 70%);
  pointer-events: none;
}
.floats { position: fixed; inset: 0; z-index: 0; pointer-events: none; overflow: hidden; }
.float-el { position: absolute; animation: floatUp linear infinite; opacity: 0; }
@keyframes floatUp {
  0%   { transform: translateY(0) rotate(0deg) scale(0.8); opacity: 0; }
  8%   { opacity: 1; } 92% { opacity: 0.7; }
  100% { transform: translateY(-105vh) rotate(40deg) scale(1.1); opacity: 0; }
}
.hero { position: relative; z-index: 1; width: 100%; text-align: center; padding: 56px 24px 40px; }
.hero-ribbon { display: inline-flex; align-items: center; gap: 14px; margin-bottom: 20px; }
.ribbon-line { width: 55px; height: 1px; background: linear-gradient(90deg, transparent, var(--gold-soft)); }
.ribbon-line.r { background: linear-gradient(90deg, var(--gold-soft), transparent); }
.couple-name { font-family: 'Great Vibes', cursive; font-size: clamp(2.8rem, 9vw, 5rem); color: var(--rose-deep); line-height: 1.1; text-shadow: 0 2px 24px rgba(212,96,124,0.18); }
.wedding-label { font-family: 'Playfair Display', serif; font-size: clamp(0.75rem, 2.5vw, 0.9rem); letter-spacing: 0.32em; text-transform: uppercase; color: var(--text-s); margin-top: 10px; }
.hero-photo { width: 220px; height: 280px; object-fit: cover; border-radius: 24px; border: 3px solid #f5d5de; box-shadow: 0 8px 40px rgba(212,96,124,0.22), 0 0 0 6px #fff; margin: 18px auto 4px; display: block; }
.hero-divider { display: flex; align-items: center; justify-content: center; gap: 10px; margin: 18px auto 0; }
.hdiv-line { width: 80px; height: 1px; background: linear-gradient(90deg, transparent, var(--rose)); }
.hdiv-line.r { background: linear-gradient(90deg, var(--rose), transparent); }
.hdiv-heart { color: var(--rose-deep); font-size: 0.9rem; }
.card {
  position: relative; z-index: 1;
  width: calc(100% - 32px); max-width: 920px;
  background: var(--ivory); border-radius: 32px;
  border: 1px solid #f5d5de;
  box-shadow: 0 1px 0 #fff inset, 0 5px 0 #f2c8d4, 0 16px 60px var(--shadow);
  padding: 40px 36px 48px; overflow: hidden;
}
.card::before {
  content: ''; position: absolute; top: 0; left: 0; right: 0; height: 6px;
  background: repeating-linear-gradient(90deg, var(--rose-light) 0px, var(--rose-light) 8px, transparent 8px, transparent 12px, var(--rose-light) 12px, var(--rose-light) 18px, transparent 18px, transparent 24px);
  border-radius: 32px 32px 0 0;
}
.card-deco { position: absolute; font-size: 3.5rem; opacity: 0.07; pointer-events: none; font-family: 'Great Vibes', cursive; color: var(--rose-deep); }
.card-deco.tl { top: 12px; left: 18px; }
.card-deco.br { bottom: 12px; right: 18px; transform: rotate(180deg); }
.stage-area { margin-bottom: 36px; display: flex; gap: 12px; align-items: stretch; }
.stage { position: relative; flex: 1; background: linear-gradient(135deg, var(--petal), var(--rose-light), var(--petal)); border: 1px solid var(--rose); border-radius: 20px; text-align: center; padding: 20px 24px 16px; overflow: hidden; }
.stage::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px; background: linear-gradient(90deg, var(--rose-light), var(--rose), var(--gold-soft), var(--rose), var(--rose-light)); }
.stage-emoji { font-size: 1.4rem; }
.stage-th { font-family: 'Playfair Display', serif; font-size: 1rem; font-weight: 700; letter-spacing: 0.14em; color: var(--rose-deep); margin-top: 4px; }
.stage-en { font-size: 0.68rem; letter-spacing: 0.28em; text-transform: uppercase; color: var(--text-s); margin-top: 3px; }
.stage-arrow { display: flex; justify-content: center; margin-top: 10px; gap: 6px; }
.arrow-dot { width: 6px; height: 6px; border-radius: 50%; background: var(--rose); animation: bounce 1.4s ease-in-out infinite; }
.arrow-dot:nth-child(2) { animation-delay: 0.2s; background: var(--rose-deep); }
.arrow-dot:nth-child(3) { animation-delay: 0.4s; }
@keyframes bounce { 0%,100% { transform: translateY(0); } 50% { transform: translateY(4px); } }
.band-box { position: relative; width: 130px; flex-shrink: 0; background: linear-gradient(135deg, var(--rose-pale), var(--petal)); border: 1px solid var(--rose); border-radius: 20px; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 5px; padding: 16px 10px; overflow: hidden; }
.band-box::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px; background: linear-gradient(90deg, var(--rose-light), var(--gold-soft), var(--rose-light)); }
.band-emoji { font-size: 1.3rem; }
.band-th { font-family: 'Playfair Display', serif; font-size: 0.75rem; font-weight: 700; letter-spacing: 0.1em; color: var(--rose-deep); text-align: center; margin-top: 2px; }
.band-en { font-size: 0.6rem; letter-spacing: 0.2em; text-transform: uppercase; color: var(--text-s); text-align: center; }
.band-notes { display: flex; gap: 3px; margin-top: 4px; }
.band-note { font-size: 0.9rem; animation: noteFloat 2s ease-in-out infinite; }
.band-note:nth-child(2) { animation-delay: 0.4s; }
.band-note:nth-child(3) { animation-delay: 0.8s; }
@keyframes noteFloat { 0%,100%{transform:translateY(0) rotate(-5deg); opacity:0.7;} 50%{transform:translateY(-4px) rotate(5deg); opacity:1;} }
@media (max-width: 560px) { .stage-area { flex-direction: column; } .band-box { width: 100%; flex-direction: row; gap: 10px; padding: 12px 16px; } }
.col-headers { display: grid; grid-template-columns: 1fr 64px 1fr; margin-bottom: 16px; }
.col-h { text-align: center; font-family: 'Playfair Display', serif; font-size: 0.7rem; letter-spacing: 0.22em; text-transform: uppercase; color: var(--text-s); }
.tables-grid { display: grid; grid-template-columns: 1fr 64px 1fr; align-items: start; }
.col { display: flex; flex-direction: column; gap: 16px; }
.aisle { display: flex; flex-direction: column; align-items: center; padding: 4px 0; }
.aisle-seg { flex: 1; width: 1px; background: linear-gradient(to bottom, transparent, #f5c8d4, transparent); }
.aisle-rose { font-size: 1rem; line-height: 1; margin: 6px 0; animation: sway 3s ease-in-out infinite; }
.aisle-rose:nth-child(3) { animation-delay: 1s; }
.aisle-rose:nth-child(5) { animation-delay: 2s; }
@keyframes sway { 0%,100% { transform: rotate(-8deg); } 50% { transform: rotate(8deg); } }
.tcard {
  background: white;
  border: 1.5px solid #f5dce4;
  border-radius: 18px;
  padding: 14px 16px 14px 14px;
  display: flex; align-items: center; gap: 14px;
  cursor: pointer;
  transition: transform 0.22s ease, box-shadow 0.22s ease;
  position: relative; overflow: hidden;
  box-shadow: 0 2px 10px rgba(212,96,124,0.06);
  text-decoration: none; color: inherit;
}
.tcard::after {
  content: ''; position: absolute;
  left: 0; top: 6px; bottom: 6px; width: 3px;
  background: linear-gradient(to bottom, var(--rose-light), var(--rose), var(--rose-light));
  border-radius: 0 3px 3px 0;
}
.tcard:hover { transform: translateY(-3px) scale(1.015); box-shadow: 0 10px 32px var(--shadow); }
.table-icon { flex-shrink: 0; width: 72px; height: 72px; }
.tlabel { flex: 1; min-width: 0; display: flex; flex-direction: column; gap: 3px; }
.tth { font-size: 0.82rem; font-weight: 500; color: var(--text-b); letter-spacing: 0.06em; }
.ten { font-family: 'Playfair Display', serif; font-size: 0.64rem; font-style: italic; color: var(--text-s); }
.tbadge { font-size: 0.56rem; font-weight: 600; letter-spacing: 0.12em; text-transform: uppercase; background: var(--rose-deep); color: white; padding: 3px 9px; border-radius: 20px; opacity: 0; transition: opacity 0.4s; white-space: nowrap; box-shadow: 0 2px 8px rgba(212,96,124,0.3); }
.tright { display: flex; flex-direction: column; align-items: flex-end; gap: 6px; flex-shrink: 0; }
.tseat-info { display: flex; flex-direction: column; align-items: flex-end; gap: 2px; }
.tseat-num { font-size: 1.6rem; line-height: 1; }
.tseat-label { font-size: 0.58rem; letter-spacing: 0.14em; text-transform: uppercase; color: var(--text-s); text-align: right; }
.tcard-ornament { display: flex; gap: 3px; align-items: center; opacity: 0.4; }
.tcard-ornament span { font-size: 0.55rem; color: var(--rose-deep); }
.tcard.active .tseat-num { color: var(--green); }
.tcard.active .tcard-ornament { opacity: 0.6; }
.tcard.active .tcard-ornament span { color: var(--green-dark); }
.tcard.active { background: var(--green-pale); border-color: var(--green); animation: greenPulse 1.8s ease-in-out infinite; }
.tcard.active::after { background: linear-gradient(to bottom, #a8ecc8, var(--green), #a8ecc8); }
.tcard.active .tth  { color: #2a7a50; }
.tcard.active .ten  { color: #5aad80; }
.tcard.active .tbadge { opacity: 1; background: var(--green-dark); }
@keyframes greenPulse {
  0%,100% { box-shadow: 0 0 0 0   rgba(107,191,142,0.35); border-color: var(--green); }
  50%      { box-shadow: 0 0 0 12px rgba(107,191,142,0);   border-color: #8dd8b0; }
}
.info-strip { margin-top: 32px; background: linear-gradient(135deg, var(--petal), var(--rose-light), var(--petal)); border: 1px solid var(--rose); border-radius: 18px; padding: 18px 22px; text-align: center; line-height: 1.7; }
.info-main { font-family: 'Playfair Display', serif; font-size: 1rem; color: var(--text-h); }
.info-main strong { font-size: 1.3rem; color: var(--rose-deep); font-style: italic; }
.info-sub { font-size: 0.76rem; color: var(--text-s); margin-top: 4px; letter-spacing: 0.06em; }
.info-warn { font-size: 0.88rem; color: #b85070; font-family: 'Playfair Display', serif; }
.legend { display: flex; justify-content: center; gap: 28px; margin-top: 24px; }
.leg { display: flex; align-items: center; gap: 8px; font-size: 0.74rem; color: var(--text-s); }
.leg-sw { width: 16px; height: 16px; border-radius: 6px; border: 1.5px solid; }
.leg-sw.pink  { background: white; border-color: #f5dce4; }
.leg-sw.green { background: var(--green-pale); border-color: var(--green); }
footer { position: relative; z-index: 1; margin-top: 32px; text-align: center; font-family: 'Great Vibes', cursive; font-size: 1.6rem; color: var(--rose); opacity: 0.7; }
@media (max-width: 560px) {
  .card { padding: 24px 14px 32px; width: calc(100% - 20px); }
  .tables-grid { grid-template-columns: 1fr 36px 1fr; }
  .col-headers  { grid-template-columns: 1fr 36px 1fr; }
  .tcard { padding: 10px 10px; gap: 8px; }
  .table-icon { width: 56px; height: 56px; }
  .tbadge { display: none; }
  .couple-name { font-size: 2.4rem; }
  .hero-photo { width: 160px; height: 200px; }
}
</style>
</head>
<body>

<div class="floats" id="floats"></div>

<div class="hero">
  <div class="hero-ribbon">
    <div class="ribbon-line"></div>
    <span style="font-size:1.2rem">💍</span>
    <div class="ribbon-line r"></div>
  </div>
  <div class="couple-name">Ball &hearts; Mint</div>
  <div class="wedding-label">ผังที่นั่งงานแต่งงาน · Seating Chart</div>
  <img class="hero-photo" src="data:image/jpeg;base64," alt="Ball & Mint">
  <div class="hero-divider">
    <div class="hdiv-line"></div>
    <span class="hdiv-heart">♥</span>
    <div class="hdiv-line r"></div>
  </div>
</div>

<div class="card">
  <span class="card-deco tl">♡</span>
  <span class="card-deco br">♡</span>
  <div class="stage-area">
    <div class="band-box">
      <div class="band-emoji">🎸</div>
      <div class="band-th">วงดนตรี</div>
      <div class="band-en">Live Band</div>
    </div>
    <div class="stage">
      <div class="stage-emoji">💐 🎤 💐</div>
      <div class="stage-th">เวที · พิธีกร</div>
      <div class="stage-en">Stage &amp; Ceremony</div>
    </div>
  </div>
  <div class="col-headers">
    <div class="col-h">ฝั่งซ้าย</div>
    <div></div>
    <div class="col-h">ฝั่งขวา</div>
  </div>
  <div class="tables-grid">
    <div class="col" id="col-left"></div>
    <div class="aisle">
      <div class="aisle-seg"></div>
      <div class="aisle-rose">🌸</div>
      <div class="aisle-seg"></div>
      <div class="aisle-rose">🌸</div>
      <div class="aisle-seg"></div>
      <div class="aisle-rose">🌸</div>
      <div class="aisle-seg"></div>
    </div>
    <div class="col" id="col-right"></div>
  </div>
  <div class="info-strip" id="info"></div>
  <div class="legend">
    <div class="leg"><div class="leg-sw pink"></div> โต๊ะทั่วไป</div>
    <div class="leg"><div class="leg-sw green"></div> โต๊ะของคุณ</div>
  </div>
</div>

<footer>With Love ♡</footer>

<script>
const params = new URLSearchParams(window.location.search);
const target = parseInt(params.get('id'), 10) || 0;
const symbols = ['🌸','💕','🌷','✿','💗','🌺','❀','💖'];
const fc = document.getElementById('floats');
for (let i = 0; i < 22; i++) {
  const el = document.createElement('div');
  el.className = 'float-el';
  el.textContent = symbols[i % symbols.length];
  el.style.cssText = `left:${Math.random()*100}%;bottom:${-5-Math.random()*10}%;font-size:${0.6+Math.random()*1}rem;animation-duration:${10+Math.random()*18}s;animation-delay:${-Math.random()*28}s;`;
  fc.appendChild(el);
}
function makeTableSVG(id, active) {
  const S = 72, cx = 36, cy = 36;
  const tablecloth  = active ? '#c8f0dc' : '#fff0f4';
  const tableRim    = active ? '#4caf7d' : '#e8a0b4';
  const tableInner  = active ? '#e0f7ec' : '#fdf4f7';
  const rimAccent   = active ? '#3a9d6b' : '#d4607c';
  const chairFill   = active ? '#d4f5e6' : '#fff5f8';
  const chairStroke = active ? '#4caf7d' : '#e8a0b4';
  const chairPad    = active ? '#a8ecc8' : '#f9dde6';
  const numColor    = active ? '#1a5e35' : '#7a3349';
  const goldRim     = active ? '#7ecfab' : '#e8c49a';
  const dotColor    = active ? '#3a9d6b' : '#d4607c';
  const heartColor  = active ? '#3a9d6b' : '#e8a0b4';
  const chairCount = 8, orb = 27, cw = 8, ch = 6;
  let chairs = '';
  for (let i = 0; i < chairCount; i++) {
    const angle = (i / chairCount) * Math.PI * 2 - Math.PI / 2;
    const px = cx + orb * Math.cos(angle);
    const py = cy + orb * Math.sin(angle);
    const deg = (angle * 180 / Math.PI) + 90;
    chairs += `<g transform="rotate(${deg.toFixed(1)},${px.toFixed(1)},${py.toFixed(1)})"><rect x="${(px-cw).toFixed(1)}" y="${(py-ch-1).toFixed(1)}" width="${cw*2}" height="${ch+2}" rx="4" fill="${chairFill}" stroke="${chairStroke}" stroke-width="1.2"/><rect x="${(px-cw+2).toFixed(1)}" y="${(py-ch+1).toFixed(1)}" width="${cw*2-4}" height="${ch-1}" rx="2.5" fill="${chairPad}" stroke="${chairStroke}" stroke-width="0.6" opacity="0.9"/></g>`;
  }
  let rimDots = '';
  for (let i = 0; i < 8; i++) {
    const angle = ((i + 0.5) / 8) * Math.PI * 2 - Math.PI / 2;
    const px = cx + 16.2 * Math.cos(angle);
    const py = cy + 16.2 * Math.sin(angle);
    rimDots += `<circle cx="${px.toFixed(1)}" cy="${py.toFixed(1)}" r="1.1" fill="${dotColor}" opacity="0.5"/>`;
  }
  let petals = '';
  for (let i = 0; i < 4; i++) {
    const angle = (i / 4) * Math.PI * 2 - Math.PI / 2;
    const px = cx + 7 * Math.cos(angle);
    const py = cy + 7 * Math.sin(angle);
    const deg = (angle * 180 / Math.PI);
    petals += `<ellipse cx="${px.toFixed(1)}" cy="${py.toFixed(1)}" rx="2.6" ry="1.4" transform="rotate(${deg.toFixed(1)},${px.toFixed(1)},${py.toFixed(1)})" fill="${heartColor}" opacity="${active ? '0.35' : '0.22'}"/>`;
  }
  return `<svg viewBox="0 0 ${S} ${S}" xmlns="http://www.w3.org/2000/svg" class="table-icon">${chairs}<circle cx="${cx+1}" cy="${cy+1.5}" r="17.5" fill="rgba(0,0,0,0.07)"/><circle cx="${cx}" cy="${cy}" r="17.5" fill="${tablecloth}" stroke="${tableRim}" stroke-width="1.8"/><circle cx="${cx}" cy="${cy}" r="16.2" fill="none" stroke="${goldRim}" stroke-width="0.6" opacity="0.6"/><circle cx="${cx}" cy="${cy}" r="14.8" fill="none" stroke="${rimAccent}" stroke-width="0.55" stroke-dasharray="2.2 2.8" opacity="0.45"/>${rimDots}<circle cx="${cx}" cy="${cy}" r="12.5" fill="${tableInner}" stroke="${tableRim}" stroke-width="0.8" opacity="0.8"/><circle cx="${cx}" cy="${cy}" r="10.5" fill="none" stroke="${rimAccent}" stroke-width="0.4" opacity="0.3"/>${petals}<circle cx="${cx}" cy="${cy}" r="1.8" fill="${dotColor}" opacity="0.4"/><text x="${cx}" y="${cy - 5}" text-anchor="middle" dominant-baseline="central" font-family="Playfair Display, serif" font-size="9.5" font-weight="700" fill="${numColor}">${id}</text></svg>`;
}
function makeCard(id) {
  const active = id === target;
  const d = document.createElement('div');
  d.className = 'tcard' + (active ? ' active' : '');
  d.id = 'tbl-' + id;
  d.innerHTML = `${makeTableSVG(id, active)}<div class="tlabel"><div class="tth">โต๊ะที่ ${id}</div><div class="ten">Table ${id}</div><div style="margin-top:5px">${active ? `<div class="tbadge" style="opacity:1;background:var(--green-dark)">✓ ที่ของคุณ</div>` : `<div class="tbadge">✓ ที่ของคุณ</div>`}</div></div><div class="tright"><div class="tseat-info"><div class="tseat-num">🌸</div></div><div class="tcard-ornament"><span>✦</span><span>♥</span><span>✦</span></div></div>`;
  return d;
}
const L = document.getElementById('col-left');
const R = document.getElementById('col-right');
for (let i = 1;  i <= 10; i++) L.appendChild(makeCard(i));
for (let i = 11; i <= 20; i++) R.appendChild(makeCard(i));
const info = document.getElementById('info');
if (target >= 1 && target <= 20) {
  info.innerHTML = `<div class="info-main">🌸 &nbsp;คุณได้รับการจัดที่นั่งที่ <strong>โต๊ะ ${target}</strong>&nbsp; 🌸</div><div class="info-sub">กรุณานั่งตามที่จัดไว้ให้ — Please take your seat at Table ${target}</div>`;
  setTimeout(() => document.getElementById('tbl-'+target)?.scrollIntoView({ behavior:'smooth', block:'center' }), 600);
} else if (params.has('table')) {
  info.innerHTML = `<div class="info-warn">⚠️ ไม่พบโต๊ะหมายเลข "${params.get('table')}" — กรุณาติดต่อเจ้าหน้าที่</div>`;
} else {
  info.innerHTML = `<div style="font-family:'Great Vibes',cursive;font-size:2.6rem;color:var(--rose-deep);line-height:1.2;text-shadow:0 2px 16px rgba(212,96,124,0.18)">Ball &hearts; Mint</div><div style="display:flex;align-items:center;justify-content:center;gap:10px;margin:8px 0"><div style="width:44px;height:1px;background:linear-gradient(90deg,transparent,var(--rose))"></div><span style="color:var(--gold);font-size:0.75rem">✦</span><div style="width:44px;height:1px;background:linear-gradient(90deg,var(--rose),transparent)"></div></div><div style="font-family:'Playfair Display',serif;font-style:italic;font-size:0.95rem;color:var(--text-b);letter-spacing:0.06em">Together Forever</div><div style="font-family:'Great Vibes',cursive;font-size:1.35rem;color:var(--rose);margin-top:2px;opacity:0.85">Two souls, one heart</div>`;
}
</script>
</body>
</html>